let app,auth,db,session=null,settings={},orders=[],stock=[],services=[],expenses=[],receivables=[],cashMovements=[],users=[],movements=[],unsubs=[],currentPage='dashboard',stockTab='tires',selectedCashDate=new Date().toISOString().slice(0,10),ordersViewFilter='open',historyTab='clients',historySearch='',pendingOrderPrefill=null;
function show(id){['loading','configView','loginView','setupView','appView'].forEach(x=>qs('#'+x)?.classList.add('hidden'));qs('#'+id)?.classList.remove('hidden')}
function toast(msg){const e=qs('#toast');e.textContent=msg;e.classList.remove('hidden');clearTimeout(e._t);e._t=setTimeout(()=>e.classList.add('hidden'),3500)}
function configured(){const c=window.FIREBASE_CONFIG||{};return c.apiKey&&!c.apiKey.includes('COLE_AQUI')&&c.projectId&&!c.projectId.includes('COLE_AQUI')}
function isAdmin(){return session?.role==='admin'}
function can(p){return isAdmin()||session?.permissions?.[p]===true}
function modal(html){qs('#modalBody').innerHTML=html;qs('#modal').classList.remove('hidden')}
function closeModal(){qs('#modal').classList.add('hidden');qs('#modalBody').innerHTML=''}
function clearListeners(){unsubs.forEach(fn=>fn());unsubs=[]}
function selectOptions(arr,selected='',custom=true){return arr.map(x=>`<option value="${x}" ${String(selected)===String(x)?'selected':''}>${x}</option>`).join('')+(custom?`<option value="custom" ${selected==='custom'?'selected':''}>Outro / personalizado</option>`:'')}
function permissionsOf(u){return {...DEFAULT_PERMS,...(u?.permissions||{})}}
function onlyDigits(v){return String(v||'').replace(/\D/g,'')}
function brPhone(v){const n=onlyDigits(v);return n.startsWith('55')?n:`55${n}`}
function localDateValue(v){if(!v)return'';if(typeof v==='string')return v.slice(0,10);const d=v?.toDate?.()||new Date(v);return Number.isNaN(d.getTime())?'':`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`}
function dueDateObj(r){const v=r?.dueDate;if(!v)return null;if(typeof v==='string'){const [y,m,d]=v.slice(0,10).split('-').map(Number);return new Date(y,m-1,d,23,59,59)}return v?.toDate?.()||new Date(v)}
function receivableStatus(r){if(Number(r.balance||0)<=0||r.status==='recebida')return'recebida';if(Number(r.paid||0)>0)return'parcial';const d=dueDateObj(r),today=new Date();today.setHours(23,59,59,999);if(d&&d<new Date(new Date().setHours(0,0,0,0)))return'vencida';if(d&&d.toDateString()===new Date().toDateString())return'hoje';return'aberta'}
function receivableMessage(r,reminder=false){const business=settings.businessName||'Borracharia';const due=dueDateObj(r)?.toLocaleDateString('pt-BR')||'não informada';return reminder?`Olá, ${r.customer}. Passando para lembrar que ${receivableStatus(r)==='vencida'?'está vencido':'vence hoje'} o pagamento combinado com a ${business}.\n\nSaldo pendente: ${money(r.balance)}\nData combinada: ${due}\n\nCaso já tenha realizado o pagamento, desconsidere esta mensagem.`:`Olá, ${r.customer}.\nSeguem os dados do pagamento combinado com a ${business}:\n\nValor da venda: ${money(r.total)}\nPago na hora: ${money(r.paid)}\nSaldo pendente: ${money(r.balance)}\nData combinada: ${due}\nStatus: Em aberto\n\nAgradecemos pela preferência.`}
function openWhatsApp(r,reminder=false){const phone=brPhone(r.phone);if(phone.length<12)return toast('Cadastre um telefone válido com DDD.');window.open(`https://wa.me/${phone}?text=${encodeURIComponent(receivableMessage(r,reminder))}`,'_blank')}
function orderNumberOf(o){
 if(o?.orderNumber)return String(o.orderNumber);
 const d=dateOf(o),stamp=`${d.getFullYear()}${String(d.getMonth()+1).padStart(2,'0')}${String(d.getDate()).padStart(2,'0')}`;
 return `OS-${stamp}-${String(o?.id||'000000').slice(0,6).toUpperCase()}`;
}
function newOrderNumber(){
 const d=new Date(),stamp=`${d.getFullYear()}${String(d.getMonth()+1).padStart(2,'0')}${String(d.getDate()).padStart(2,'0')}-${String(d.getHours()).padStart(2,'0')}${String(d.getMinutes()).padStart(2,'0')}${String(d.getSeconds()).padStart(2,'0')}`;
 return `OS-${stamp}-${Math.floor(10+Math.random()*90)}`;
}
function receiptLines(o){
 const items=Array.isArray(o.items)&&o.items.length?o.items:[{serviceName:o.serviceName||o.service||'Serviço',qty:1,unitPrice:o.subtotal??o.value??0}];
 return items.map(i=>({description:[i.serviceName,i.vehicleType,i.chamberType,i.material].filter(Boolean).join(' - '),qty:Number(i.qty||1),unit:Number(i.unitPrice||0),total:Number(i.qty||1)*Number(i.unitPrice||0)}));
}
function receiptHtml(o){
 const rows=receiptLines(o).map(i=>`<tr><td>${esc(i.description)}</td><td>${i.qty}</td><td>${money(i.unit)}</td><td>${money(i.total)}</td></tr>`).join('');
 const logo=settings.logoData?`<img src="${settings.logoData}" alt="Logo">`:'';
 return `<div class="receipt-sheet">${logo}<h1>${esc(settings.businessName||'Borracharia')}</h1><p>${esc(settings.address||'')}${settings.phone?`<br>${esc(settings.phone)}`:''}</p><hr><div class="receipt-meta"><strong>Ordem: ${esc(orderNumberOf(o))}</strong><span>Data: ${dateOf(o).toLocaleString('pt-BR')}</span><span>Status: ${statusLabel(o.status)}</span></div><p><strong>Cliente:</strong> ${esc(o.customer||'')}<br><strong>Telefone:</strong> ${esc(o.phone||'')}<br><strong>Veículo:</strong> ${esc(o.vehicleType||'')} ${esc(o.vehicle||'')} ${o.plate?`— Placa ${esc(o.plate)}`:''}</p><table><thead><tr><th>Serviço</th><th>Qtd.</th><th>Unitário</th><th>Total</th></tr></thead><tbody>${rows}</tbody></table><div class="receipt-totals"><span>Subtotal: ${money(o.subtotal??o.value)}</span>${Number(o.adjustment||0)!==0?`<span>Ajuste comercial: ${money(o.adjustment)}</span>`:''}<strong>Valor final: ${money(o.value)}</strong><span>Pagamento: ${esc(o.payment||'Não informado')}</span></div>${o.notes?`<p><strong>Observações:</strong> ${esc(o.notes)}</p>`:''}<div class="receipt-signatures"><span>________________________________<br>Responsável</span><span>________________________________<br>Cliente</span></div><p class="receipt-footer">Obrigado pela preferência.</p></div>`;
}
function openReceipt(o){
 modal(`<div class="receipt-toolbar"><h2>Recibo ${esc(orderNumberOf(o))}</h2><div class="actions"><button id="printReceiptBtn" class="btn btn-primary">Imprimir / salvar PDF</button><button id="shareReceiptPdfBtn" class="btn btn-success">Enviar PDF</button></div></div><div id="receiptPreview">${receiptHtml(o)}</div>`);
 qs('#printReceiptBtn').onclick=()=>printReceipt(o);
 qs('#shareReceiptPdfBtn').onclick=()=>shareReceiptPdf(o);
}
function printReceipt(o){
 const w=window.open('','_blank');if(!w)return toast('Permita pop-ups para imprimir.');
 w.document.write(`<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width"><title>${esc(orderNumberOf(o))}</title><style>body{font-family:Arial,sans-serif;color:#111;padding:20px}.receipt-sheet{max-width:760px;margin:auto}.receipt-sheet img{max-width:120px;max-height:90px;display:block;margin:auto}.receipt-sheet h1{text-align:center;margin:8px 0}.receipt-sheet>p{text-align:center}.receipt-meta{display:flex;justify-content:space-between;gap:12px;flex-wrap:wrap}table{width:100%;border-collapse:collapse;margin:18px 0}th,td{border-bottom:1px solid #bbb;padding:9px;text-align:left}.receipt-totals{margin-left:auto;max-width:340px;display:grid;gap:7px;text-align:right}.receipt-signatures{display:flex;justify-content:space-between;gap:40px;margin-top:60px;text-align:center}.receipt-footer{text-align:center;margin-top:40px}@media print{body{padding:0}}</style></head><body>${receiptHtml(o)}<script>setTimeout(()=>window.print(),400)<\/script></body></html>`);w.document.close();
}
async function buildReceiptPdf(o){
 if(!window.jspdf?.jsPDF)throw new Error('Gerador de PDF ainda não carregou.');
 const {jsPDF}=window.jspdf,pdf=new jsPDF({unit:'mm',format:'a4'}),left=15,right=195;let y=16;
 if(settings.logoData){try{pdf.addImage(settings.logoData,'JPEG',82,8,46,28);y=40}catch{}}
 pdf.setFont('helvetica','bold');pdf.setFontSize(16);pdf.text(settings.businessName||'Borracharia',105,y,{align:'center'});y+=7;
 pdf.setFont('helvetica','normal');pdf.setFontSize(9);if(settings.address){pdf.text(String(settings.address),105,y,{align:'center'});y+=5}if(settings.phone){pdf.text(String(settings.phone),105,y,{align:'center'});y+=5}
 pdf.line(left,y,right,y);y+=7;pdf.setFont('helvetica','bold');pdf.setFontSize(12);pdf.text(`RECIBO - ${orderNumberOf(o)}`,left,y);y+=7;
 pdf.setFont('helvetica','normal');pdf.setFontSize(10);const meta=[`Data: ${dateOf(o).toLocaleString('pt-BR')}`,`Cliente: ${o.customer||''}`,`Telefone: ${o.phone||''}`,`Veículo: ${[o.vehicleType,o.vehicle,o.plate&&'Placa '+o.plate].filter(Boolean).join(' - ')}`];for(const line of meta){pdf.text(pdf.splitTextToSize(line,180),left,y);y+=6}
 y+=2;pdf.setFont('helvetica','bold');pdf.text('Serviço',left,y);pdf.text('Qtd.',132,y);pdf.text('Unit.',150,y);pdf.text('Total',176,y);y+=3;pdf.line(left,y,right,y);y+=6;pdf.setFont('helvetica','normal');
 for(const i of receiptLines(o)){const desc=pdf.splitTextToSize(i.description,110);pdf.text(desc,left,y);pdf.text(String(i.qty),136,y,{align:'right'});pdf.text(money(i.unit).replace(/ /g,' '),170,y,{align:'right'});pdf.text(money(i.total).replace(/ /g,' '),right,y,{align:'right'});y+=Math.max(6,desc.length*5);if(y>265){pdf.addPage();y=18}}
 y+=3;pdf.line(left,y,right,y);y+=7;pdf.setFont('helvetica','bold');pdf.text(`Valor final: ${money(o.value).replace(/ /g,' ')}`,right,y,{align:'right'});y+=6;pdf.setFont('helvetica','normal');pdf.text(`Pagamento: ${o.payment||'Não informado'}`,right,y,{align:'right'});y+=12;if(o.notes){pdf.text(pdf.splitTextToSize(`Observações: ${o.notes}`,180),left,y);y+=12}
 pdf.text('________________________________',left,275);pdf.text('________________________________',120,275);pdf.text('Responsável',38,281,{align:'center'});pdf.text('Cliente',148,281,{align:'center'});return pdf;
}
async function shareReceiptPdf(o){
 try{const pdf=await buildReceiptPdf(o),blob=pdf.output('blob'),file=new File([blob],`${orderNumberOf(o)}.pdf`,{type:'application/pdf'});if(navigator.canShare?.({files:[file]})){await navigator.share({title:`Recibo ${orderNumberOf(o)}`,text:`Recibo da ${settings.businessName||'borracharia'}`,files:[file]});}else{pdf.save(`${orderNumberOf(o)}.pdf`);toast('PDF baixado. Abra-o e compartilhe pelo WhatsApp.')}}catch(err){console.error(err);toast(err.message||'Não foi possível gerar o PDF.');}
}


if(!configured())show('configView');else init();
async function init(){
 app=initializeApp(window.FIREBASE_CONFIG);auth=getAuth(app);db=getFirestore(app);await setPersistence(auth,browserSessionPersistence);qs('#tenantInfo').textContent=`Borracharia: ${tenant}`;bindStatic();
 onAuthStateChanged(auth,async user=>{clearListeners();if(!user){session=null;await loadPublicBrand();show('loginView');return}const p=await getDoc(doc(db,'tenants',tenant,'users',user.uid));if(!p.exists()||p.data().active===false){await signOut(auth);toast('Usuário sem acesso ou bloqueado.');return}session={uid:user.uid,...p.data(),permissions:permissionsOf(p.data())};window._dueAlertShown=false;startRealtime();show('appView');buildMenu();navigate('dashboard')});
}
function bindStatic(){
 // Bloqueio global de reconstrução enquanto qualquer campo estiver sendo digitado.
 document.addEventListener('focusin',e=>{
   if(e.target.matches('input,textarea,select,[contenteditable="true"]')){
     clearTimeout(formInteractionTimer);
     formInteractionLock=true;
   }
 },true);
 document.addEventListener('focusout',e=>{
   if(e.target.matches('input,textarea,select,[contenteditable="true"]')){
     clearTimeout(formInteractionTimer);
     formInteractionTimer=setTimeout(()=>{formInteractionLock=false},1200);
   }
 },true);
 document.addEventListener('beforeinput',e=>{
   if(e.target.matches('input,textarea,[contenteditable="true"]')){
     clearTimeout(formInteractionTimer);
     formInteractionLock=true;
   }
 },true);
 qs('#showSetupBtn').onclick=()=>show('setupView');qs('#backLoginBtn').onclick=()=>show('loginView');qs('#logoutBtn').onclick=()=>signOut(auth);qs('#modalClose').onclick=closeModal;qs('#modal').onclick=e=>{if(e.target.id==='modal')closeModal()};
 qs('#loginForm').onsubmit=async e=>{e.preventDefault();try{show('loading');await signInWithEmailAndPassword(auth,emailFor(qs('#loginUser').value),qs('#loginPassword').value)}catch(err){console.error(err);show('loginView');toast('Usuário ou senha inválidos.')}};
 qs('#setupForm').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target);try{show('loading');const cred=await createUserWithEmailAndPassword(auth,emailFor(f.get('username')),f.get('password'));await setDoc(doc(db,'tenants',tenant),{businessName:f.get('businessName'),phone:'',address:'',primaryColor:'#f59e0b',logoData:'',ownerUid:cred.user.uid,createdAt:serverTimestamp()});await setDoc(doc(db,'tenants',tenant,'users',cred.user.uid),{name:f.get('name'),username:String(f.get('username')).toLowerCase(),role:'admin',active:true,permissions:{},createdAt:serverTimestamp()});toast('Sistema criado com sucesso.')}catch(err){console.error(err);show('setupView');toast('Não foi possível criar. O usuário pode já existir ou as regras precisam ser atualizadas.')}};
}
async function loadPublicBrand(){try{const t=await getDoc(doc(db,'tenants',tenant));const exists=t.exists();settings=exists?t.data():{businessName:'Controle da Borracharia',primaryColor:'#f59e0b',logoData:''};qs('#showSetupBtn')?.classList.toggle('hidden',exists)}catch{settings={businessName:'Controle da Borracharia',primaryColor:'#f59e0b',logoData:''};qs('#showSetupBtn')?.classList.remove('hidden')}applyBrand()}
function applyBrand(){document.documentElement.style.setProperty('--primary',settings.primaryColor||'#f59e0b');qs('#loginBusinessName').textContent=settings.businessName||'Controle da Borracharia';qs('#headerBusinessName').textContent=settings.businessName||'Borracharia';const has=!!settings.logoData;[['#loginLogo','#loginLogoFallback'],['#headerLogo','#headerLogoFallback']].forEach(([i,f])=>{qs(i).classList.toggle('hidden',!has);qs(f).classList.toggle('hidden',has);if(has)qs(i).src=settings.logoData})}
function startRealtime(){
 unsubs.push(onSnapshot(doc(db,'tenants',tenant),s=>{settings=s.data()||{};applyBrand();refresh()}));
 if(can('ordersView'))unsubs.push(onSnapshot(query(collection(db,'tenants',tenant,'orders'),orderBy('createdAt','desc')),s=>{orders=s.docs.map(d=>({id:d.id,...d.data()}));refresh()}));
 if(can('stockView')){unsubs.push(onSnapshot(collection(db,'tenants',tenant,'stock'),s=>{stock=s.docs.map(d=>({id:d.id,...d.data()}));refresh()}));unsubs.push(onSnapshot(query(collection(db,'tenants',tenant,'stockMovements'),orderBy('createdAt','desc')),s=>{movements=s.docs.map(d=>({id:d.id,...d.data()}));refresh()}))}
 unsubs.push(onSnapshot(collection(db,'tenants',tenant,'services'),s=>{services=s.docs.map(d=>({id:d.id,...d.data()}));refresh()}));
 if(can('cashView')){unsubs.push(onSnapshot(collection(db,'tenants',tenant,'expenses'),s=>{expenses=s.docs.map(d=>({id:d.id,...d.data()}));refresh()}));unsubs.push(onSnapshot(query(collection(db,'tenants',tenant,'receivables'),orderBy('createdAt','desc')),s=>{receivables=s.docs.map(d=>({id:d.id,...d.data()}));refresh();showDueAlert()}));unsubs.push(onSnapshot(query(collection(db,'tenants',tenant,'cashMovements'),orderBy('createdAt','desc')),s=>{cashMovements=s.docs.map(d=>({id:d.id,...d.data()}));refresh()}))}
 if(can('usersManage'))unsubs.push(onSnapshot(collection(db,'tenants',tenant,'users'),s=>{users=s.docs.map(d=>({id:d.id,...d.data(),permissions:permissionsOf(d.data())}));refresh()}));
 qs('#roleBadge').textContent=isAdmin()?'Administrador':'Funcionário';
}
function refresh(){
  if(qs('#appView').classList.contains('hidden'))return;

  // Nunca reconstrói a interface enquanto o usuário estiver com teclado/campo ativo.
  const active=document.activeElement;
  const editing=!!active && active.matches?.('input,textarea,select,[contenteditable="true"]');
  if(formInteractionLock || editing)return;

  // Protege permanentemente os formulários principais.
  if(currentPage==='newOrder')return;
  const modalOpen=!qs('#modal')?.classList.contains('hidden');
  if(modalOpen)return;

  navigate(currentPage||'dashboard',false);
}
function buildMenu(){const items=[['dashboard','Painel',true],['orders','Ordens de serviço',can('ordersView')],['history','Clientes e veículos',can('ordersView')],['newOrder','Nova ordem',can('ordersCreate')],['stock','Estoque',can('stockView')],['services','Serviços e preços',can('servicesManage')],['movements','Movimentações',can('stockView')],['cash','Caixa',can('cashView')],['receivables','Contas a receber',can('cashView')],['reports','Relatórios',isAdmin()],['users','Usuários',can('usersManage')],['profile','Minha conta',true],['settings','Personalização',can('settingsManage')]];qs('#sidebar').innerHTML=items.filter(x=>x[2]).map(([id,l])=>`<button class="nav-btn" data-page="${id}">${l}</button>`).join('');qsa('.nav-btn').forEach(b=>b.onclick=()=>navigate(b.dataset.page))}
function navigate(page,scroll=true){currentPage=page;qsa('.page').forEach(p=>p.classList.add('hidden'));const target=qs(`#${page}Page`);if(!target)return;target.classList.remove('hidden');qsa('.nav-btn').forEach(b=>b.classList.toggle('active',b.dataset.page===page));const fn={dashboard:renderDashboard,orders:renderOrders,history:renderHistory,newOrder:renderNewOrder,stock:renderStock,services:renderServices,movements:renderMovements,cash:renderCash,receivables:renderReceivables,reports:renderReports,users:renderUsers,profile:renderProfile,settings:renderSettings}[page];fn?.();if(scroll)window.scrollTo({top:0,behavior:'smooth'})}
function ordersTable(list){if(!list.length)return'<div class="empty">Nenhuma ordem cadastrada.</div>';return`<div class="table-wrap"><table><thead><tr><th>Ordem</th><th>Data</th><th>Cliente</th><th>Veículo</th><th>Serviços</th><th>Subtotal</th><th>Valor final</th><th>Status</th><th>Funcionário</th></tr></thead><tbody>${list.map(o=>{const summary=(o.items||[]).map(i=>`${i.qty||1}x ${i.serviceName}${i.vehicleType?` (${i.vehicleType})`:''}${i.chamberType?` — ${i.chamberType}`:''}${i.material?` / ${i.material}`:''}`).join('<br>')||esc(o.serviceName||o.service||'Serviço');return`<tr><td><strong>${esc(orderNumberOf(o))}</strong></td><td>${dateOf(o).toLocaleDateString('pt-BR')}</td><td>${esc(o.customer)}<br><span class="muted">${esc(o.phone||'')}</span></td><td>${esc(o.vehicle||o.vehicleType||'')}<br><span class="muted">${esc(o.plate||'')}</span></td><td>${summary}</td><td>${money(o.subtotal??o.value)}</td><td><strong>${money(o.value)}</strong>${Number(o.adjustment||0)!==0?`<br><span class="muted">Ajuste: ${money(o.adjustment)}</span>`:''}</td><td><span class="status status-${o.status}">${statusLabel(o.status)}</span></td><td>${esc(o.employee||'')}</td></tr>`}).join('')}</tbody></table></div>`}

function renderDashboard(){const today=new Date().toDateString(),tod=orders.filter(o=>dateOf(o).toDateString()===today),rev=tod.filter(o=>o.status==='concluida').reduce((a,o)=>a+Number(o.value||0),0),low=stock.filter(i=>Number(i.qty)<=Number(i.min||0)).length,openOrders=orders.filter(o=>['aberta','execucao'].includes(o.status));const cards=[`<div class="card"><div class="stat-label">Serviços hoje</div><div class="stat-value">${tod.length}</div></div>`,isAdmin()?`<div class="card"><div class="stat-label">Faturamento hoje</div><div class="stat-value">${money(rev)}</div></div>`:'',`<div class="card"><div class="stat-label">Em aberto</div><div class="stat-value">${openOrders.length}</div></div>`,`<div class="card"><div class="stat-label">Estoque baixo</div><div class="stat-value">${low}</div></div>`].join('');qs('#dashboardPage').innerHTML=`<h1 class="page-title">Painel</h1><div class="grid ${isAdmin()?'grid-4':'grid-3'}">${cards}</div>${can('cashView')?receivableAlertHtml():''}<div class="card" style="margin-top:16px"><h3>Ordens em aberto</h3>${ordersTable(openOrders.slice(0,5))}</div>`}
function completedDate(o){return o?.completedAt?.toDate?.()||null}
function cancelledDate(o){return o?.cancelledAt?.toDate?.()||o?.updatedAt?.toDate?.()||dateOf(o)}
function cancelledIsArchived(o){const d=cancelledDate(o);return !!d&&Date.now()-d.getTime()>=24*60*60*1000}
function orderLocked(o){if(o?.status!=='concluida')return false;const d=completedDate(o);return !d||Date.now()>=d.getTime()+60000}
function canEditOrder(o){return isAdmin()||(can('ordersEdit')&&!orderLocked(o))}
function orderSnapshot(o){return{customer:o.customer||'',phone:o.phone||'',vehicleType:o.vehicleType||'',vehicle:o.vehicle||'',plate:o.plate||'',items:(o.items||[]).map(i=>({...i})),subtotal:Number(o.subtotal||0),value:Number(o.value||0),adjustment:Number(o.adjustment||0),adjustmentReason:o.adjustmentReason||'',payment:o.payment||'',status:o.status||'aberta',notes:o.notes||''}}
function stockTotals(items=[]){const m={};items.forEach(i=>{if(i.stockId)m[i.stockId]=(m[i.stockId]||0)+Number(i.stockQty||1)});return m}
async function updateExistingOrder(o,data,reason=''){
 const oldUse=stockTotals(o.items||[]),newUse=stockTotals(data.items||[]),ids=[...new Set([...Object.keys(oldUse),...Object.keys(newUse)])],movementRows=[];
 const orderRef=doc(db,'tenants',tenant,'orders',o.id),historyRef=doc(collection(db,'tenants',tenant,'orders',o.id,'history'));
 await runTransaction(db,async tx=>{
  for(const id of ids){const ref=doc(db,'tenants',tenant,'stock',id),snap=await tx.get(ref);if(!snap.exists())throw new Error('Um item de estoque não foi encontrado.');const delta=Number(newUse[id]||0)-Number(oldUse[id]||0),cur=Number(snap.data().qty||0),next=cur-delta;if(next<0)throw new Error(`Estoque insuficiente para ${stockName({id,...snap.data()})}`);if(delta!==0){tx.update(ref,{qty:next,updatedAt:serverTimestamp()});movementRows.push({id,item:stockName({id,...snap.data()}),delta,previous:cur,next})}}
  const payload={...data,updatedAt:serverTimestamp(),lastEditedBy:session.uid,lastEditedByName:session.name,lastEditedByUsername:session.username||''};
  tx.update(orderRef,payload);
  if(isAdmin())tx.set(historyRef,{adminUid:session.uid,adminName:session.name,adminUsername:session.username||'',reason:reason||'Edição administrativa',before:orderSnapshot(o),after:{...orderSnapshot(o),...data},createdAt:serverTimestamp()});
 });
 for(const m of movementRows)await addDoc(collection(db,'tenants',tenant,'stockMovements'),{stockId:m.id,itemName:m.item,type:m.delta>0?'saida':'entrada',qty:Math.abs(m.delta),previousQty:m.previous,newQty:m.next,reason:`Ajuste da ordem ${o.id}`,employee:session.name,createdBy:session.uid,createdAt:serverTimestamp()});
}
async function showOrderHistory(o){if(!isAdmin())return;const snap=await getDocs(query(collection(db,'tenants',tenant,'orders',o.id,'history'),orderBy('createdAt','desc'))),rows=snap.docs.map(d=>d.data());modal(`<h2>Histórico da ordem</h2>${rows.length?rows.map(h=>`<div class="card" style="margin-bottom:12px"><strong>${esc(h.adminName||'Administrador')}</strong> (${esc(h.adminUsername||'')})<br><span class="muted">${h.createdAt?.toDate?.().toLocaleString('pt-BR')||'Agora'}</span><p><strong>Motivo:</strong> ${esc(h.reason||'')}</p><p><strong>Valor:</strong> ${money(h.before?.value)} → ${money(h.after?.value)}<br><strong>Status:</strong> ${statusLabel(h.before?.status)} → ${statusLabel(h.after?.status)}</p></div>`).join(''):'<div class="empty">Nenhuma edição administrativa registrada.</div>'}`)}

function normText(v){return String(v||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().replace(/[^a-z0-9]/g,'')}
function cleanPlate(v){return String(v||'').toUpperCase().replace(/[^A-Z0-9]/g,'')}
function customerKey(o){const phone=onlyDigits(o.phone);return phone?`p:${phone}`:`n:${normText(o.customer)}`}
function completedOrdersOf(list){return list.filter(o=>o.status==='concluida')}
function customerGroups(){
 const map=new Map();
 orders.filter(o=>o.customer||o.phone).forEach(o=>{const k=customerKey(o);if(!k||k==='n:')return;let g=map.get(k);if(!g){g={key:k,name:o.customer||'Cliente sem nome',phone:o.phone||'',orders:[],vehicles:new Map()};map.set(k,g)};g.orders.push(o);if(o.customer)g.name=o.customer;if(o.phone)g.phone=o.phone;const pk=cleanPlate(o.plate)||`${normText(o.vehicle)}:${normText(o.vehicleType)}`;if(pk&&pk!==':'){let v=g.vehicles.get(pk);if(!v){v={key:pk,plate:o.plate||'',vehicle:o.vehicle||'',vehicleType:o.vehicleType||'',orders:[]};g.vehicles.set(pk,v)}v.orders.push(o);if(o.plate)v.plate=o.plate;if(o.vehicle)v.vehicle=o.vehicle;if(o.vehicleType)v.vehicleType=o.vehicleType}});
 return [...map.values()].map(g=>{g.orders.sort((a,b)=>dateOf(b)-dateOf(a));g.vehicles=[...g.vehicles.values()].map(v=>({...v,orders:v.orders.sort((a,b)=>dateOf(b)-dateOf(a))}));const done=completedOrdersOf(g.orders);g.totalSpent=done.reduce((a,o)=>a+Number(o.value||0),0);g.lastDate=g.orders[0]?dateOf(g.orders[0]):null;g.firstDate=g.orders.length?dateOf(g.orders[g.orders.length-1]):null;g.pending=receivables.filter(r=>Number(r.balance||0)>0&&(onlyDigits(r.phone)===onlyDigits(g.phone)||normText(r.customer)===normText(g.name))).reduce((a,r)=>a+Number(r.balance||0),0);return g}).sort((a,b)=>(b.lastDate||0)-(a.lastDate||0))
}
function vehicleGroups(){
 const map=new Map();orders.filter(o=>o.plate||o.vehicle).forEach(o=>{const k=cleanPlate(o.plate)||`${normText(o.vehicle)}:${normText(o.vehicleType)}`;let g=map.get(k);if(!g){g={key:k,plate:o.plate||'',vehicle:o.vehicle||'',vehicleType:o.vehicleType||'',customer:o.customer||'',phone:o.phone||'',orders:[]};map.set(k,g)}g.orders.push(o);if(o.plate)g.plate=o.plate;if(o.vehicle)g.vehicle=o.vehicle;if(o.vehicleType)g.vehicleType=o.vehicleType;if(o.customer)g.customer=o.customer;if(o.phone)g.phone=o.phone});return[...map.values()].map(g=>{g.orders.sort((a,b)=>dateOf(b)-dateOf(a));g.lastDate=g.orders[0]?dateOf(g.orders[0]):null;g.totalSpent=completedOrdersOf(g.orders).reduce((a,o)=>a+Number(o.value||0),0);return g}).sort((a,b)=>(b.lastDate||0)-(a.lastDate||0))
}
function serviceHistoryStats(){const m={};orders.filter(o=>o.status==='concluida').forEach(o=>(o.items||[]).forEach(i=>{const n=i.serviceName||'Serviço não informado';m[n]??={name:n,qty:0,total:0};m[n].qty+=Number(i.qty||1);m[n].total+=Number(i.qty||1)*Number(i.unitPrice||0)}));return Object.values(m).sort((a,b)=>b.qty-a.qty)}
function historyOrderRows(list){return list.map(o=>`<tr><td>${dateOf(o).toLocaleDateString('pt-BR')}</td><td>${esc(o.customer||'')}</td><td>${esc(o.plate||o.vehicle||'')}</td><td>${esc(o.serviceName||'')}</td><td>${statusLabel(o.status)}</td><td>${money(o.value)}</td></tr>`).join('')||'<tr><td colspan="6" class="empty">Nenhum serviço encontrado.</td></tr>'}
function openCustomerHistory(key){const g=customerGroups().find(x=>x.key===key);if(!g)return;modal(`<div class="history-detail"><h2>${esc(g.name)}</h2><p class="muted">${esc(g.phone||'Telefone não informado')}</p><div class="grid grid-4"><div class="card"><div class="stat-label">Atendimentos</div><div class="stat-value">${g.orders.length}</div></div><div class="card"><div class="stat-label">Último serviço</div><div class="stat-value history-date">${g.lastDate?.toLocaleDateString('pt-BR')||'-'}</div></div><div class="card"><div class="stat-label">Total concluído</div><div class="stat-value">${money(g.totalSpent)}</div></div><div class="card"><div class="stat-label">Saldo pendente</div><div class="stat-value">${money(g.pending)}</div></div></div><div class="toolbar history-actions"><h3>Veículos vinculados</h3>${can('ordersCreate')?`<button class="btn btn-primary historyNewOrder" data-customer="${esc(g.key)}">Nova ordem para cliente</button>`:''}</div><div class="history-vehicle-list">${g.vehicles.map(v=>`<button class="history-vehicle-chip openVehicleFromCustomer" data-key="${esc(v.key)}"><strong>${esc(v.plate||v.vehicle||'Veículo')}</strong><span>${esc(v.vehicleType||'')} • ${v.orders.length} atendimento(s)</span></button>`).join('')||'<div class="empty compact">Nenhum veículo identificado.</div>'}</div><h3 class="subheading">Todos os serviços do cliente</h3><div class="table-wrap"><table><thead><tr><th>Data</th><th>Cliente</th><th>Veículo</th><th>Serviços</th><th>Status</th><th>Valor</th></tr></thead><tbody>${historyOrderRows(g.orders)}</tbody></table></div></div>`);qs('.historyNewOrder')&&(qs('.historyNewOrder').onclick=()=>startOrderFromHistory({customer:g.name,phone:g.phone,vehicleType:g.vehicles[0]?.vehicleType||'Carro',vehicle:g.vehicles[0]?.vehicle||'',plate:g.vehicles[0]?.plate||''}));qsa('.openVehicleFromCustomer').forEach(b=>b.onclick=()=>openVehicleHistory(b.dataset.key))}
function openVehicleHistory(key){const g=vehicleGroups().find(x=>x.key===key);if(!g)return;modal(`<div class="history-detail"><h2>${esc(g.plate||g.vehicle||'Veículo')}</h2><p class="muted">${esc(g.vehicleType||'')} ${g.vehicle?'• '+esc(g.vehicle):''}</p><div class="grid grid-4"><div class="card"><div class="stat-label">Cliente mais recente</div><div class="stat-value history-name">${esc(g.customer||'-')}</div></div><div class="card"><div class="stat-label">Atendimentos</div><div class="stat-value">${g.orders.length}</div></div><div class="card"><div class="stat-label">Último serviço</div><div class="stat-value history-date">${g.lastDate?.toLocaleDateString('pt-BR')||'-'}</div></div><div class="card"><div class="stat-label">Total concluído</div><div class="stat-value">${money(g.totalSpent)}</div></div></div>${can('ordersCreate')?'<div class="actions history-actions"><button id="newOrderForVehicle" class="btn btn-primary">Nova ordem para este veículo</button></div>':''}<h3 class="subheading">Histórico do veículo</h3><div class="table-wrap"><table><thead><tr><th>Data</th><th>Cliente</th><th>Veículo</th><th>Serviços</th><th>Status</th><th>Valor</th></tr></thead><tbody>${historyOrderRows(g.orders)}</tbody></table></div></div>`);qs('#newOrderForVehicle')&&(qs('#newOrderForVehicle').onclick=()=>startOrderFromHistory({customer:g.customer,phone:g.phone,vehicleType:g.vehicleType||'Carro',vehicle:g.vehicle,plate:g.plate}))}
function startOrderFromHistory(data){pendingOrderPrefill=data;closeModal();navigate('newOrder')}
function renderHistory(){
 if(!can('ordersView'))return;
 const page=qs('#historyPage');
 if(!page)return;

 // Monta a estrutura apenas uma vez. Enquanto o usuário digita,
 // somente a lista de resultados é atualizada; o campo não é recriado.
 if(!qs('#historySearch')){
  page.innerHTML=`<div class="toolbar"><h1 class="page-title">Clientes e veículos</h1></div><div class="card history-search-card"><label>Pesquisa geral<input id="historySearch" value="${esc(historySearch)}" placeholder="Nome, telefone, placa, veículo ou serviço" autocomplete="off"></label><div class="history-tabs"><button class="btn historyTab" data-tab="clients">Clientes <span class="historyCount" data-count="clients"></span></button><button class="btn historyTab" data-tab="vehicles">Veículos <span class="historyCount" data-count="vehicles"></span></button><button class="btn historyTab" data-tab="general">Pesquisa geral <span class="historyCount" data-count="general"></span></button><button class="btn historyTab" data-tab="insights">Outros históricos</button></div></div><div id="historyResults"></div>`;

  const input=qs('#historySearch');
  input.oninput=e=>{
   historySearch=e.target.value;
   clearTimeout(input._t);
   input._t=setTimeout(updateHistoryResults,120);
  };
  qsa('.historyTab').forEach(b=>b.onclick=()=>{
   historyTab=b.dataset.tab;
   updateHistoryResults();
  });
 }
 updateHistoryResults();
}

function updateHistoryResults(){
 const input=qs('#historySearch');
 const result=qs('#historyResults');
 if(!input||!result)return;
 const customers=customerGroups(),vehicles=vehicleGroups(),q=normText(historySearch);
 const match=o=>!q||normText([o.customer,o.phone,o.plate,o.vehicle,o.vehicleType,o.serviceName].join(' ')).includes(q);
 const general=orders.filter(match).sort((a,b)=>dateOf(b)-dateOf(a));
 const filteredCustomers=customers.filter(g=>!q||normText([g.name,g.phone,...g.vehicles.map(v=>`${v.plate} ${v.vehicle} ${v.vehicleType}`)].join(' ')).includes(q));
 const filteredVehicles=vehicles.filter(g=>!q||normText([g.plate,g.vehicle,g.vehicleType,g.customer,g.phone].join(' ')).includes(q));
 const serviceStats=serviceHistoryStats().slice(0,10);

 qsa('.historyTab').forEach(b=>b.classList.toggle('active',b.dataset.tab===historyTab));
 const counts={clients:filteredCustomers.length,vehicles:filteredVehicles.length,general:general.length};
 qsa('.historyCount').forEach(s=>s.textContent=`(${counts[s.dataset.count]??0})`);

 if(historyTab==='clients')result.innerHTML=`<div class="history-card-grid">${filteredCustomers.map(g=>`<button class="card history-record openCustomer" data-key="${esc(g.key)}"><div><strong>${esc(g.name)}</strong><span>${esc(g.phone||'Sem telefone')}</span></div><div class="history-record-meta"><span>${g.orders.length} atendimento(s)</span><span>Último: ${g.lastDate?.toLocaleDateString('pt-BR')||'-'}</span><span>${g.vehicles.length} veículo(s)</span></div></button>`).join('')||'<div class="card empty">Nenhum cliente encontrado.</div>'}</div>`;
 else if(historyTab==='vehicles')result.innerHTML=`<div class="history-card-grid">${filteredVehicles.map(g=>`<button class="card history-record openVehicle" data-key="${esc(g.key)}"><div><strong>${esc(g.plate||g.vehicle||'Veículo')}</strong><span>${esc(g.vehicleType||'')} ${g.vehicle?'• '+esc(g.vehicle):''}</span></div><div class="history-record-meta"><span>Cliente: ${esc(g.customer||'-')}</span><span>${g.orders.length} atendimento(s)</span><span>Último: ${g.lastDate?.toLocaleDateString('pt-BR')||'-'}</span></div></button>`).join('')||'<div class="card empty">Nenhum veículo encontrado.</div>'}</div>`;
 else if(historyTab==='general')result.innerHTML=`<div class="card table-wrap"><table><thead><tr><th>Data</th><th>Cliente</th><th>Veículo</th><th>Serviços</th><th>Status</th><th>Valor</th></tr></thead><tbody>${historyOrderRows(general)}</tbody></table></div>`;
 else result.innerHTML=`<div class="grid grid-2"><div class="card"><h3>Serviços mais realizados</h3>${serviceStats.map((s,i)=>`<div class="history-ranking"><strong>${i+1}. ${esc(s.name)}</strong><span>${s.qty} unidade(s) • ${money(s.total)}</span></div>`).join('')||'<div class="empty compact">Sem dados.</div>'}</div><div class="card"><h3>Atendimentos por tipo de veículo</h3>${Object.entries(orders.reduce((m,o)=>(m[o.vehicleType||'Não informado']=(m[o.vehicleType||'Não informado']||0)+1,m),{})).sort((a,b)=>b[1]-a[1]).map(([n,v])=>`<div class="history-ranking"><strong>${esc(n)}</strong><span>${v} atendimento(s)</span></div>`).join('')}</div><div class="card"><h3>Atendimentos por funcionário</h3>${Object.entries(orders.reduce((m,o)=>(m[o.employee||'Não informado']=(m[o.employee||'Não informado']||0)+1,m),{})).sort((a,b)=>b[1]-a[1]).map(([n,v])=>`<div class="history-ranking"><strong>${esc(n)}</strong><span>${v} ordem(ns)</span></div>`).join('')}</div><div class="card"><h3>Resumo histórico</h3><div class="history-ranking"><strong>Clientes identificados</strong><span>${customers.length}</span></div><div class="history-ranking"><strong>Veículos identificados</strong><span>${vehicles.length}</span></div><div class="history-ranking"><strong>Total de ordens</strong><span>${orders.length}</span></div><div class="history-ranking"><strong>Ordens concluídas</strong><span>${orders.filter(o=>o.status==='concluida').length}</span></div></div></div>`;
 qsa('.openCustomer').forEach(b=>b.onclick=()=>openCustomerHistory(b.dataset.key));
 qsa('.openVehicle').forEach(b=>b.onclick=()=>openVehicleHistory(b.dataset.key));
}

function renderOrders(){
 if(!can('ordersView'))return;
 const openOrders=orders.filter(o=>['aberta','execucao'].includes(o.status));
 const completedOrders=orders.filter(o=>o.status==='concluida');
 const cancelledRecent=orders.filter(o=>o.status==='cancelada'&&!cancelledIsArchived(o));
 const cancelledArchived=orders.filter(o=>o.status==='cancelada'&&cancelledIsArchived(o));
 const selected=ordersViewFilter==='completed'?completedOrders:ordersViewFilter==='cancelled'?cancelledRecent:ordersViewFilter==='archive'?cancelledArchived:openOrders;
 const title={open:'Ordens em aberto',completed:'Ordens concluídas',cancelled:'Canceladas recentes',archive:'Arquivo de canceladas'}[ordersViewFilter];
 const rows=selected.map(o=>{const locked=orderLocked(o),remaining=o.status==='concluida'&&!locked&&completedDate(o)?Math.max(0,Math.ceil((completedDate(o).getTime()+60000-Date.now())/1000)):null;return`<div class="order-manage-card"><div><strong>${esc(orderNumberOf(o))}</strong> — ${esc(o.customer)} — ${esc(o.plate||o.vehicle||'')}<br><span class="muted">${statusLabel(o.status)} • ${money(o.value)}${locked?' • Bloqueada':remaining!==null?` • bloqueia em ${remaining}s`:''}${o.status==='cancelada'?` • cancelada em ${cancelledDate(o).toLocaleString('pt-BR')}`:''}</span></div><div class="actions">${o.status!=='cancelada'?`<button class="btn btn-small btn-success receiptOrder" data-id="${o.id}">Recibo / PDF</button>`:''}${canEditOrder(o)&&o.status!=='cancelada'?`<button class="btn btn-small btn-primary editOrder" data-id="${o.id}">Editar ordem</button>`:''}${isAdmin()?`<button class="btn btn-small btn-secondary orderHistory" data-id="${o.id}">Histórico</button>`:''}${isAdmin()&&o.status==='cancelada'?`<button class="btn btn-small btn-danger deleteCancelledOrder" data-id="${o.id}">Excluir definitivamente</button>`:''}</div></div>`}).join('');
 qs('#ordersPage').innerHTML=`<div class="toolbar"><h1 class="page-title">Ordens de serviço</h1>${can('ordersCreate')?'<button id="goNewOrder" class="btn btn-primary">Nova ordem</button>':''}</div><div class="order-filter-tabs"><button class="btn orderFilter ${ordersViewFilter==='open'?'active':''}" data-filter="open">Em aberto <span>${openOrders.length}</span></button><button class="btn orderFilter ${ordersViewFilter==='completed'?'active':''}" data-filter="completed">Concluídas <span>${completedOrders.length}</span></button><button class="btn orderFilter ${ordersViewFilter==='cancelled'?'active':''}" data-filter="cancelled">Canceladas <span>${cancelledRecent.length}</span></button><button class="btn orderFilter ${ordersViewFilter==='archive'?'active':''}" data-filter="archive">Arquivo <span>${cancelledArchived.length}</span></button></div><div class="card"><h3>${title}</h3>${ordersTable(selected)}</div><div class="card" style="margin-top:16px"><h3>Gerenciar ${title.toLowerCase()}</h3><p class="muted small">A tela abre mostrando somente ordens abertas ou em execução. Ordens canceladas ficam separadas; após 24 horas passam automaticamente para o Arquivo de canceladas. Administradores podem excluir definitivamente cancelamentos feitos para teste ou por erro.</p>${rows||'<div class="empty">Nenhuma ordem nesta lista.</div>'}</div>`;
 qs('#goNewOrder')&&(qs('#goNewOrder').onclick=()=>navigate('newOrder'));
 qsa('.orderFilter').forEach(b=>b.onclick=()=>{ordersViewFilter=b.dataset.filter;renderOrders()});
 qsa('.receiptOrder').forEach(b=>b.onclick=()=>openReceipt(orders.find(o=>o.id===b.dataset.id)));
 qsa('.editOrder').forEach(b=>b.onclick=()=>openOrderEditor(orders.find(o=>o.id===b.dataset.id)));
 qsa('.orderHistory').forEach(b=>b.onclick=()=>showOrderHistory(orders.find(o=>o.id===b.dataset.id)));
 qsa('.deleteCancelledOrder').forEach(b=>b.onclick=()=>confirmDeleteCancelledOrder(orders.find(o=>o.id===b.dataset.id)));
}
async function confirmDeleteCancelledOrder(o){
 if(!isAdmin()||o?.status!=='cancelada')return;
 modal(`<h2>Excluir ordem cancelada</h2><div class="warning-box"><strong>Atenção:</strong> esta ação é definitiva. Use somente para ordens de teste ou canceladas por erro de preenchimento.</div><p><strong>${esc(o.customer||'Sem cliente')}</strong><br>${esc(o.plate||o.vehicle||'')} • ${money(o.value)}</p><form id="deleteCancelledForm" class="form-stack"><label>Motivo da exclusão<select name="reason" required><option value="">Selecione</option><option>Ordem criada para teste</option><option>Erro de preenchimento</option><option>Cadastro duplicado</option><option>Outro motivo</option></select></label><label>Confirme digitando EXCLUIR<input name="confirm" autocomplete="off" required></label><button class="btn btn-danger">Excluir definitivamente</button></form>`);
 qs('#deleteCancelledForm').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target);if(String(f.get('confirm')).trim().toUpperCase()!=='EXCLUIR')return toast('Digite EXCLUIR para confirmar.');try{await deleteDoc(doc(db,'tenants',tenant,'orders',o.id));toast(`Ordem excluída: ${f.get('reason')}.`);closeModal()}catch(err){console.error(err);toast('Não foi possível excluir. Verifique se você é administrador.')}};
}
