  qsa('.li-material').forEach(el=>{el.value=lineItems[Number(el.dataset.i)].material||'';el.onchange=()=>{lineItems[Number(el.dataset.i)].material=el.value;renderSummary()}});
  qsa('.li-qty').forEach(el=>el.onchange=()=>{lineItems[Number(el.dataset.i)].qty=Math.max(1,Number(el.value||1));renderLines();recalc()});
  qsa('.li-price').forEach(el=>el.oninput=()=>{lineItems[Number(el.dataset.i)].unitPrice=Number(el.value||0);recalc()});
