function renderMeasureFields(item){const category=qs('#tireCategory').value,special=['Quadriciclo','Carrinho de mão','Agrícola','Implemento/reboque'].includes(category),m=item?.measure||'';if(special){const parts=m.replace(/^AT\s*/,'').split(/[x-]/);qs('#measureFields').innerHTML=`<div class="form-grid"><label>Diâmetro externo<select id="spDiameter" name="spDiameter">${selectOptions(SPECIAL_DIAMETERS,parts[0]||'')}</select></label><label>Largura<select id="spWidth" name="spWidth">${selectOptions(SPECIAL_WIDTHS,parts[1]||'')}</select></label><label>Aro<select id="spRim" name="spRim">${selectOptions(RIMS,parts[2]||'')}</select></label><label>Medida personalizada<input name="customMeasure" value="${esc(parts.length<3?m:'')}" placeholder="Ex.: 4.10/3.50-4"></label><div class="full measure-preview" id="measurePreview"></div></div>`}else{const p=m.match(/(\d+)\/(\d+)\s*R?([\d.]+)/i)||[];qs('#measureFields').innerHTML=`<div class="form-grid"><label>Largura<select id="width" name="width">${selectOptions(WIDTHS,p[1]||'')}</select></label><label>Altura/perfil<select id="profile" name="profile">${selectOptions(PROFILES,p[2]||'')}</select></label><label>Aro<select id="rim" name="rim">${selectOptions(RIMS,p[3]||'')}</select></label><label>Medida personalizada<input name="customMeasure" value="${esc(!p.length?m:'')}" placeholder="Ex.: 31x10.50 R15"></label><div class="full measure-preview" id="measurePreview"></div></div>`}const upd=()=>{const f=new FormData(qs('#stockEditForm'));qs('#measurePreview').textContent=buildMeasure(f)||'Selecione a medida'};qsa('#measureFields select,#measureFields input').forEach(x=>x.oninput=upd);upd()}
