function renderMovements(){if(!can('stockView'))return;qs('#movementsPage').innerHTML=`<h1 class="page-title">Movimentações do estoque</h1><div class="card table-wrap"><table><thead><tr><th>Data</th><th>Item</th><th>Tipo</th><th>Quantidade</th><th>Motivo</th><th>Responsável</th></tr></thead><tbody>${movements.map(m=>`<tr><td>${dateOf(m).toLocaleString('pt-BR')}</td><td>${esc(m.itemName)}</td><td><span class="status ${m.type==='saida'?'status-danger':'status-ok'}">${esc(m.type)}</span></td><td>${m.qty}</td><td>${esc(m.reason||'')}</td><td>${esc(m.employee||'')}</td></tr>`).join('')||'<tr><td colspan="6" class="empty">Nenhuma movimentação.</td></tr>'}</tbody></table></div>`}
function paymentBucket(method){
 const m=String(method||'Não informado').toLowerCase();
 if(m.includes('pix'))return'Pix';
 if(m.includes('dinheiro'))return'Dinheiro';
 if(m.includes('débito')||m.includes('debito'))return'Cartão de débito';
 if(m.includes('crédito')||m.includes('credito'))return'Cartão de crédito';
 if(m.includes('cartão')||m.includes('cartao'))return'Cartão não especificado';
 return'Não informado';
}
function paymentSummary(){
 const totals={'Dinheiro':0,'Pix':0,'Cartão de débito':0,'Cartão de crédito':0,'Cartão não especificado':0,'Não informado':0};
 orders.filter(o=>o.status==='concluida'&&!['Fiado','A prazo'].includes(o.payment)).forEach(o=>totals[paymentBucket(o.payment)]+=Number(o.value||0));
 receivables.forEach(r=>{
  const pt=r.paymentTotals||{};let identified=0;
  Object.entries(pt).forEach(([method,value])=>{const v=Number(value||0);totals[paymentBucket(method)]+=v;identified+=v});
  const missing=Math.max(0,Number(r.paid||0)-identified);if(missing>0)totals['Não informado']+=missing;
 });
 return totals;
}
function cashDateKey(value){const d=value?.toDate?.()||value instanceof Date&&value||null;if(!d)return'';const y=d.getFullYear(),m=String(d.getMonth()+1).padStart(2,'0'),day=String(d.getDate()).padStart(2,'0');return`${y}-${m}-${day}`}
function renderCash(){
 if(!can('cashView'))return;
 const day=selectedCashDate||new Date().toISOString().slice(0,10);
 const dayOrders=orders.filter(o=>o.status==='concluida'&&cashDateKey(o.completedAt||o.createdAt)===day);
 const dayExpenses=expenses.filter(x=>cashDateKey(x.createdAt)===day);
 const dayMovements=cashMovements.filter(x=>cashDateKey(x.createdAt)===day);
 const methods={'Dinheiro':0,'Pix':0,'Cartão de débito':0,'Cartão de crédito':0,'Cartão não especificado':0,'Não informado':0};
 dayMovements.filter(x=>x.type==='receita').forEach(x=>methods[paymentBucket(x.method)]+=Number(x.amount||0));
 // Compatibilidade: ordens antigas podem não possuir cashMovement.
 dayOrders.filter(o=>!['Fiado','A prazo'].includes(o.payment)&&!dayMovements.some(m=>m.orderId===o.id&&m.source==='ordem')).forEach(o=>methods[paymentBucket(o.payment)]+=Number(o.value||0));
 const sales=dayOrders.reduce((a,o)=>a+Number(o.value||0),0),received=Object.values(methods).reduce((a,v)=>a+Number(v||0),0),exp=dayExpenses.reduce((a,x)=>a+Number(x.value||0),0);
 const cards=Object.entries(methods).map(([name,value])=>`<div class="card"><div class="stat-label">${esc(name)}</div><div class="stat-value">${money(value)}</div></div>`).join('');
 const rows=[...dayMovements.map(x=>({time:dateOf(x),kind:'Recebimento',description:x.description||x.source||'Receita',method:x.method||'',in:Number(x.amount||0),out:0,employee:x.employee||''})),...dayExpenses.map(x=>({time:dateOf(x),kind:'Despesa',description:x.description||'',method:'',in:0,out:Number(x.value||0),employee:x.employee||''}))].sort((a,b)=>b.time-a.time);
 qs('#cashPage').innerHTML=`<div class="toolbar"><h1 class="page-title">Caixa e movimento diário</h1><label class="cash-date-filter">Selecionar dia<input id="cashDateFilter" type="date" value="${day}"></label></div><div class="grid grid-4"><div class="card"><div class="stat-label">Vendas concluídas no dia</div><div class="stat-value">${money(sales)}</div></div><div class="card"><div class="stat-label">Recebido no dia</div><div class="stat-value">${money(received)}</div></div><div class="card"><div class="stat-label">Despesas no dia</div><div class="stat-value">${money(exp)}</div></div><div class="card"><div class="stat-label">Saldo do dia</div><div class="stat-value">${money(received-exp)}</div></div></div><h2 class="subheading">Recebimentos por modalidade — ${new Date(day+'T12:00:00').toLocaleDateString('pt-BR')}</h2><div class="grid grid-3 payment-method-grid">${cards}</div>${can('cashEdit')?`<form id="expenseForm" class="card form-grid" style="margin-top:16px"><label>Descrição<input name="description" required></label><label>Valor<input name="value" type="number" min="0" step="0.01" required></label><div class="full"><button class="btn btn-primary">Registrar despesa agora</button></div></form>`:''}<div class="card table-wrap" style="margin-top:16px"><h3>Movimentação do dia selecionado</h3><table><thead><tr><th>Hora</th><th>Tipo</th><th>Descrição</th><th>Modalidade</th><th>Entrada</th><th>Saída</th><th>Responsável</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${x.time.toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'})}</td><td>${esc(x.kind)}</td><td>${esc(x.description)}</td><td>${esc(x.method)}</td><td>${x.in?money(x.in):'-'}</td><td>${x.out?money(x.out):'-'}</td><td>${esc(x.employee)}</td></tr>`).join('')||'<tr><td colspan="7" class="empty">Nenhuma movimentação neste dia.</td></tr>'}</tbody></table></div><div class="card table-wrap" style="margin-top:16px"><h3>Vendas do dia</h3><table><thead><tr><th>Cliente</th><th>Veículo</th><th>Serviços</th><th>Pagamento</th><th>Status</th><th>Valor</th></tr></thead><tbody>${dayOrders.map(o=>`<tr><td>${esc(o.customer||'')}</td><td>${esc(o.plate||o.vehicle||'')}</td><td>${esc(o.serviceName||'')}</td><td>${esc(o.payment||'')}</td><td>${statusLabel(o.status)}</td><td>${money(o.value)}</td></tr>`).join('')||'<tr><td colspan="6" class="empty">Nenhuma venda concluída neste dia.</td></tr>'}</tbody></table></div>`;
 qs('#cashDateFilter').onchange=e=>{selectedCashDate=e.target.value;renderCash()};
 qs('#expenseForm')&&(qs('#expenseForm').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target);await addDoc(collection(db,'tenants',tenant,'expenses'),{description:f.get('description'),value:Number(f.get('value')),employee:session.name,createdAt:serverTimestamp()});toast('Despesa registrada.');e.target.reset()})
}

function receivableAlertHtml(){
 const due=receivables.filter(r=>['hoje','vencida'].includes(receivableStatus(r))),total=due.reduce((a,r)=>a+Number(r.balance||0),0);
 return `<div class="card ${due.length?'receivable-alert':''}" style="margin-top:16px"><div class="toolbar"><div><h3 style="margin:0">Contas a receber</h3><span class="muted">${due.length?`${due.length} cobrança(s) para atenção — ${money(total)}`:'Nenhuma cobrança vencendo hoje.'}</span></div><button class="btn btn-secondary" onclick="document.querySelector('[data-page=receivables]')?.click()">Abrir contas</button></div></div>`
}
function showDueAlert(){
 if(!session||!can('cashView')||window._dueAlertShown)return;
 const due=receivables.filter(r=>['hoje','vencida'].includes(receivableStatus(r)));
 if(!due.length)return;
 window._dueAlertShown=true;
 const total=due.reduce((a,r)=>a+Number(r.balance||0),0);
 modal(`<div class="due-alert-modal"><div class="due-alert-icon">!</div><h2>Contas para cobrar</h2><p class="muted">${due.length} conta(s) vencendo hoje ou vencida(s), totalizando <strong>${money(total)}</strong>.</p><div class="due-alert-list">${due.map(r=>{const st=receivableStatus(r);return`<div class="due-alert-row"><div><strong>${esc(r.customer)}</strong><br><span class="muted">${esc(r.phone||'Sem telefone')} • ${dueDateObj(r)?.toLocaleDateString('pt-BR')||'-'}</span><br><span class="status receivable-${st}">${st==='vencida'?'Vencida':'Vence hoje'}</span> <strong>${money(r.balance)}</strong></div><button class="btn btn-success dueWhatsapp" data-id="${r.id}">Enviar WhatsApp</button></div>`}).join('')}</div><div class="actions due-alert-actions"><button id="openReceivablesFromAlert" class="btn btn-primary">Abrir contas a receber</button><button id="closeDueAlert" class="btn btn-secondary">Fechar</button></div></div>`);
 qsa('.dueWhatsapp').forEach(b=>b.onclick=()=>openWhatsApp(receivables.find(r=>r.id===b.dataset.id),true));
 qs('#openReceivablesFromAlert').onclick=()=>{closeModal();navigate('receivables')};
 qs('#closeDueAlert').onclick=closeModal;
}
function renderReceivables(){
 if(!can('cashView'))return;
 const open=receivables.filter(r=>receivableStatus(r)!=='recebida'),received=receivables.filter(r=>receivableStatus(r)==='recebida'),total=open.reduce((a,r)=>a+Number(r.balance||0),0),today=open.filter(r=>receivableStatus(r)==='hoje'),overdue=open.filter(r=>receivableStatus(r)==='vencida');
 const label={aberta:'Em aberto',hoje:'Vence hoje',vencida:'Vencida',parcial:'Parcial',recebida:'Recebida'};
 qs('#receivablesPage').innerHTML=`<h1 class="page-title">Contas a receber</h1><div class="grid grid-4"><div class="card"><div class="stat-label">Total a receber</div><div class="stat-value">${money(total)}</div></div><div class="card"><div class="stat-label">Vencendo hoje</div><div class="stat-value">${today.length}</div></div><div class="card"><div class="stat-label">Vencidas</div><div class="stat-value">${overdue.length}</div></div><div class="card"><div class="stat-label">Recebidas</div><div class="stat-value">${received.length}</div></div></div><div class="card table-wrap" style="margin-top:16px"><table><thead><tr><th>Ordem</th><th>Cliente</th><th>Telefone</th><th>Venda</th><th>Pago</th><th>Saldo</th><th>Data combinada</th><th>Status</th><th>Ações</th></tr></thead><tbody>${receivables.map(r=>{const st=receivableStatus(r),o=orders.find(x=>x.id===r.orderId);return`<tr><td>${esc(o?orderNumberOf(o):(r.orderNumber||'-'))}</td><td>${esc(r.customer)}</td><td>${esc(r.phone||'')}</td><td>${money(r.total)}</td><td>${money(r.paid)}</td><td><strong>${money(r.balance)}</strong></td><td>${dueDateObj(r)?.toLocaleDateString('pt-BR')||'-'}</td><td><span class="status receivable-${st}">${label[st]}</span></td><td><div class="actions">${st!=='recebida'?`<button class="btn btn-small btn-success receivePay" data-id="${r.id}">Receber</button><button class="btn btn-small btn-primary sendReminder" data-id="${r.id}">WhatsApp</button><button class="btn btn-small btn-secondary changeDue" data-id="${r.id}">Nova data</button>`:`<button class="btn btn-small btn-secondary sendReceipt" data-id="${r.id}">WhatsApp</button>`}${isAdmin()?`<button class="btn btn-small btn-danger deleteReceivable" data-id="${r.id}">Excluir lançamento</button>`:''}</div></td></tr>`}).join('')||'<tr><td colspan="9" class="empty">Nenhuma conta cadastrada.</td></tr>'}</tbody></table></div>`;
 qsa('.sendReminder').forEach(b=>b.onclick=()=>openWhatsApp(receivables.find(r=>r.id===b.dataset.id),true));qsa('.sendReceipt').forEach(b=>b.onclick=()=>openWhatsApp(receivables.find(r=>r.id===b.dataset.id),false));qsa('.receivePay').forEach(b=>b.onclick=()=>openReceivePayment(receivables.find(r=>r.id===b.dataset.id)));qsa('.changeDue').forEach(b=>b.onclick=()=>openChangeDue(receivables.find(r=>r.id===b.dataset.id)));qsa('.deleteReceivable').forEach(b=>b.onclick=()=>confirmDeleteReceivable(receivables.find(r=>r.id===b.dataset.id)));
}
async function confirmDeleteReceivable(r){
 if(!isAdmin()||!r)return;
 modal(`<h2>Excluir conta a receber</h2><div class="warning-box"><strong>Atenção:</strong> use esta opção somente para lançamento feito por engano. A ordem de serviço vinculada não será excluída.</div><p><strong>${esc(r.customer)}</strong><br>Venda: ${money(r.total)} • Pago: ${money(r.paid)} • Saldo: ${money(r.balance)}</p><form id="deleteReceivableForm" class="form-stack"><label>Motivo<input name="reason" required placeholder="Ex.: lançamento duplicado ou erro de preenchimento"></label><label>Confirme digitando EXCLUIR<input name="confirm" required autocomplete="off"></label><button class="btn btn-danger">Excluir lançamento e movimentações vinculadas</button></form>`);
 qs('#deleteReceivableForm').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target);if(String(f.get('confirm')).trim().toUpperCase()!=='EXCLUIR')return toast('Digite EXCLUIR para confirmar.');try{const payments=await getDocs(collection(db,'tenants',tenant,'receivables',r.id,'payments'));for(const p of payments.docs)await deleteDoc(p.ref);for(const m of cashMovements.filter(x=>x.receivableId===r.id))await deleteDoc(doc(db,'tenants',tenant,'cashMovements',m.id));await deleteDoc(doc(db,'tenants',tenant,'receivables',r.id));toast(`Lançamento excluído: ${f.get('reason')}`);closeModal()}catch(err){console.error(err);toast('Não foi possível excluir o lançamento.')}};
}

function openReceivePayment(r){
 modal(`<h2>Registrar recebimento</h2><p><strong>${esc(r.customer)}</strong><br>Saldo atual: ${money(r.balance)}</p><form id="receiveForm" class="form-stack"><label>Valor recebido<input name="amount" type="number" min="0.01" max="${Number(r.balance)}" step="0.01" required></label><label>Forma de recebimento<select name="method"><option>Dinheiro</option><option>Pix</option><option>Cartão de débito</option><option>Cartão de crédito</option><option>Outro</option></select></label><label>Observação<input name="notes"></label><button class="btn btn-success">Registrar pagamento</button></form>`);
 qs('#receiveForm').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target),amount=Number(f.get('amount')),method=f.get('method');if(amount<=0||amount>Number(r.balance))return toast('Informe um valor válido.');const paid=Number(r.paid||0)+amount,balance=Math.max(0,Number(r.total||0)-paid),paymentTotals={...(r.paymentTotals||{})};paymentTotals[method]=Number(paymentTotals[method]||0)+amount;await updateDoc(doc(db,'tenants',tenant,'receivables',r.id),{paid,balance,paymentTotals,status:balance<=0?'recebida':'parcial',lastPaymentAt:serverTimestamp(),updatedAt:serverTimestamp()});await addDoc(collection(db,'tenants',tenant,'receivables',r.id,'payments'),{amount,method,notes:f.get('notes')||'',receivedBy:session.name,receivedByUid:session.uid,createdAt:serverTimestamp()});await addDoc(collection(db,'tenants',tenant,'cashMovements'),{type:'receita',source:'recebimento_fiado',receivableId:r.id,orderId:r.orderId||'',description:`Recebimento fiado - ${r.customer}`,amount,method,employee:session.name,createdBy:session.uid,createdAt:serverTimestamp()});toast('Pagamento registrado.');closeModal()}
}
function openChangeDue(r){modal(`<h2>Alterar data combinada</h2><form id="dueForm" class="form-stack"><label>Nova data<input name="dueDate" type="date" value="${localDateValue(r.dueDate)}" required></label><label>Motivo<input name="reason" required></label><button class="btn btn-primary">Salvar nova data</button></form>`);qs('#dueForm').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target);await updateDoc(doc(db,'tenants',tenant,'receivables',r.id),{dueDate:f.get('dueDate'),rescheduleReason:f.get('reason'),rescheduledBy:session.name,updatedAt:serverTimestamp()});toast('Data atualizada.');closeModal()}}
function renderReports(){
 if(!isAdmin())return;
 const now=new Date(),startWeek=new Date(now);startWeek.setHours(0,0,0,0);startWeek.setDate(now.getDate()-((now.getDay()+6)%7));
 const endWeek=new Date(startWeek);endWeek.setDate(startWeek.getDate()+7);
 const startMonth=new Date(now.getFullYear(),now.getMonth(),1),endMonth=new Date(now.getFullYear(),now.getMonth()+1,1);
 const completed=orders.filter(o=>o.status==='concluida');
 const inRange=(o,a,b)=>{const d=dateOf(o);return d>=a&&d<b};
 const weekOrders=completed.filter(o=>inRange(o,startWeek,endWeek)),monthOrders=completed.filter(o=>inRange(o,startMonth,endMonth));
 const sum=list=>list.reduce((a,o)=>a+Number(o.value||0),0);
 const serviceStats={};
 monthOrders.forEach(o=>{
  const items=Array.isArray(o.items)&&o.items.length?o.items:[{serviceName:o.serviceName||o.service||'Serviço',qty:1,unitPrice:o.value||0}];
  items.forEach(i=>{const name=i.serviceName||'Serviço',qty=Number(i.qty||1),value=qty*Number(i.unitPrice||0);serviceStats[name]??={qty:0,value:0};serviceStats[name].qty+=qty;serviceStats[name].value+=value})
 });
 const ranking=Object.entries(serviceStats).sort((a,b)=>b[1].qty-a[1].qty).slice(0,15);
 const avg=list=>list.length?sum(list)/list.length:0;
 qs('#reportsPage').innerHTML=`<h1 class="page-title">Faturamento e relatórios</h1>
 <div class="grid grid-3">
  <div class="card"><div class="stat-label">Faturamento semanal</div><div class="stat-value">${money(sum(weekOrders))}</div><div class="muted">${weekOrders.length} ordens concluídas</div></div>
  <div class="card"><div class="stat-label">Faturamento mensal</div><div class="stat-value">${money(sum(monthOrders))}</div><div class="muted">${monthOrders.length} ordens concluídas</div></div>
  <div class="card"><div class="stat-label">Ticket médio mensal</div><div class="stat-value">${money(avg(monthOrders))}</div><div class="muted">Média por ordem concluída</div></div>
 </div>
 <div class="card table-wrap" style="margin-top:16px"><h3>Serviços mais utilizados no mês</h3><table><thead><tr><th>Posição</th><th>Serviço</th><th>Quantidade</th><th>Valor normal somado</th></tr></thead><tbody>${ranking.map(([name,x],idx)=>`<tr><td>${idx+1}º</td><td>${esc(name)}</td><td><strong>${x.qty}</strong></td><td>${money(x.value)}</td></tr>`).join('')||'<tr><td colspan="4" class="empty">Ainda não há serviços concluídos neste mês.</td></tr>'}</tbody></table></div>
 <div class="card" style="margin-top:16px"><h3>Períodos considerados</h3><p class="muted">Semana: ${startWeek.toLocaleDateString('pt-BR')} a ${new Date(endWeek.getTime()-86400000).toLocaleDateString('pt-BR')}<br>Mês: ${startMonth.toLocaleDateString('pt-BR',{month:'long',year:'numeric'})}</p></div>`
}
function renderUsers(){if(!can('usersManage'))return;qs('#usersPage').innerHTML=`<div class="toolbar"><h1 class="page-title">Usuários e autorizações</h1><button id="newUser" class="btn btn-primary">Novo usuário</button></div><div class="warning-box">Por segurança do Firebase, o administrador pode editar nome, perfil, autorizações e status. Cada usuário altera a própria senha em “Minha conta”.</div><div class="card table-wrap"><table><thead><tr><th>Nome</th><th>Usuário</th><th>Perfil</th><th>Status</th><th>Autorizações</th><th>Ações</th></tr></thead><tbody>${users.map(u=>`<tr><td>${esc(u.name)}</td><td>${esc(u.username)}</td><td>${u.role==='admin'?'Administrador':'Funcionário'}</td><td>${u.active?'Ativo':'Bloqueado'}</td><td>${u.role==='admin'?'Todas':Object.entries(PERM_LABELS).filter(([k])=>u.permissions?.[k]).map(([,l])=>l).join(', ')||'Nenhuma'}</td><td><div class="actions"><button class="btn btn-small btn-secondary editUser" data-id="${u.id}">Editar</button>${u.id!==session.uid?`<button class="btn btn-small ${u.active?'btn-danger':'btn-success'} toggleUser" data-id="${u.id}">${u.active?'Bloquear':'Ativar'}</button>`:''}</div></td></tr>`).join('')}</tbody></table></div>`;qs('#newUser').onclick=()=>openUser();qsa('.editUser').forEach(b=>b.onclick=()=>openUser(users.find(u=>u.id===b.dataset.id)));qsa('.toggleUser').forEach(b=>b.onclick=()=>{const u=users.find(x=>x.id===b.dataset.id);updateDoc(doc(db,'tenants',tenant,'users',u.id),{active:!u.active,updatedAt:serverTimestamp()})})}
function permFields(p={}){return Object.entries(PERM_LABELS).map(([k,l])=>`<label class="check-row"><input type="checkbox" name="perm_${k}" ${p[k]?'checked':''}>${l}</label>`).join('')}
function openUser(u=null){modal(`<h2>${u?'Editar usuário':'Novo usuário'}</h2><form id="userEditForm" class="form-grid"><label>Nome<input name="name" value="${esc(u?.name||'')}" required></label><label>Usuário<input name="username" value="${esc(u?.username||'')}" ${u?'readonly':''} required minlength="3"></label>${u?'':`<label>Senha inicial<input name="password" type="password" minlength="6" required></label>`}<label>Perfil<select id="userRole" name="role"><option value="employee">Funcionário</option><option value="admin">Administrador</option></select></label><label>Status<select name="active"><option value="true">Ativo</option><option value="false">Bloqueado</option></select></label><div id="permissionBox" class="full"><h3>Autorizações do funcionário</h3><div class="checkbox-grid">${permFields(u?.permissions||DEFAULT_PERMS)}</div></div><div class="full"><button class="btn btn-primary">Salvar usuário</button></div></form>`);qs('#userRole').value=u?.role||'employee';qs('[name=active]').value=String(u?.active!==false);const roleChange=()=>qs('#permissionBox').classList.toggle('hidden',qs('#userRole').value==='admin');qs('#userRole').onchange=roleChange;roleChange();qs('#userEditForm').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target),perms={};Object.keys(PERM_LABELS).forEach(k=>perms[k]=f.get(`perm_${k}`)==='on');try{if(u){await updateDoc(doc(db,'tenants',tenant,'users',u.id),{name:f.get('name'),role:f.get('role'),active:f.get('active')==='true',permissions:f.get('role')==='admin'?{}:perms,updatedAt:serverTimestamp()});if(u.id===session.uid){session={...session,name:f.get('name'),role:f.get('role'),active:f.get('active')==='true',permissions:f.get('role')==='admin'?{}:perms};buildMenu()}}else{let secondary;try{secondary=initializeApp(window.FIREBASE_CONFIG,'secondary-'+Date.now());const a=getAuth(secondary),cred=await createUserWithEmailAndPassword(a,emailFor(f.get('username')),f.get('password'));await setDoc(doc(db,'tenants',tenant,'users',cred.user.uid),{name:f.get('name'),username:String(f.get('username')).toLowerCase(),role:f.get('role'),active:f.get('active')==='true',permissions:f.get('role')==='admin'?{}:perms,createdAt:serverTimestamp()})}finally{if(secondary)await deleteApp(secondary)}}toast('Usuário salvo.');closeModal()}catch(err){console.error(err);toast('Não foi possível salvar. O nome de usuário pode já existir.')}}}
function renderProfile(){qs('#profilePage').innerHTML=`<h1 class="page-title">Minha conta</h1><form id="profileForm" class="card form-grid"><label>Nome<input name="name" value="${esc(session.name||'')}" required></label><label>Usuário<input value="${esc(session.username||'')}" disabled></label><div class="full"><button class="btn btn-primary">Salvar nome</button></div></form><form id="passwordForm" class="card form-grid" style="margin-top:16px"><label>Nova senha<input name="password" type="password" minlength="6" required></label><label>Confirmar senha<input name="confirm" type="password" minlength="6" required></label><div class="full"><button class="btn btn-secondary">Alterar minha senha</button></div></form>`;qs('#profileForm').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target);await updateDoc(doc(db,'tenants',tenant,'users',session.uid),{name:f.get('name'),updatedAt:serverTimestamp()});toast('Nome atualizado.')};qs('#passwordForm').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target);if(f.get('password')!==f.get('confirm'))return toast('As senhas não conferem.');try{await updatePassword(auth.currentUser,f.get('password'));toast('Senha alterada com sucesso.');e.target.reset()}catch(err){console.error(err);toast('Por segurança, saia e entre novamente antes de alterar a senha.')}}}
async function compressLogo(file){return new Promise((resolve,reject)=>{const img=new Image(),r=new FileReader();r.onload=()=>img.src=r.result;r.onerror=reject;img.onload=()=>{const max=500,scale=Math.min(1,max/Math.max(img.width,img.height)),c=document.createElement('canvas');c.width=Math.round(img.width*scale);c.height=Math.round(img.height*scale);c.getContext('2d').drawImage(img,0,0,c.width,c.height);resolve(c.toDataURL('image/jpeg',.78))};r.readAsDataURL(file)})}
function renderSettings(){if(!can('settingsManage'))return;qs('#settingsPage').innerHTML=`<h1 class="page-title">Personalização</h1><form id="settingsForm" class="card form-grid"><label>Nome da borracharia<input name="businessName" value="${esc(settings.businessName||'')}" required></label><label>Telefone / WhatsApp<input name="phone" value="${esc(settings.phone||'')}"></label><label class="full">Endereço<input name="address" value="${esc(settings.address||'')}"></label><label>Cor principal<input name="primaryColor" type="color" value="${settings.primaryColor||'#f59e0b'}"></label><label>Logomarca JPG ou PNG<input id="logoInput" type="file" accept="image/jpeg,image/png"></label><div class="full"><img id="settingsLogoPreview" class="preview-logo ${settings.logoData?'':'hidden'}" src="${settings.logoData||''}"></div><div class="full toolbar"><button class="btn btn-primary">Salvar personalização</button><button id="removeLogoBtn" class="btn btn-danger" type="button">Remover logomarca</button></div></form><div class="card" style="margin-top:16px"><strong>Link da borracharia:</strong><br><span class="muted">${location.origin}${location.pathname}?loja=${tenant}</span></div>`;let logo=settings.logoData||'';qs('#logoInput').onchange=async e=>{const f=e.target.files[0];if(!f)return;if(f.size>5*1024*1024)return toast('Imagem muito grande. Use até 5 MB.');logo=await compressLogo(f);qs('#settingsLogoPreview').src=logo;qs('#settingsLogoPreview').classList.remove('hidden')};qs('#removeLogoBtn').onclick=()=>{logo='';qs('#settingsLogoPreview').classList.add('hidden')};qs('#settingsForm').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target);await updateDoc(doc(db,'tenants',tenant),{businessName:f.get('businessName'),phone:f.get('phone'),address:f.get('address'),primaryColor:f.get('primaryColor'),logoData:logo,updatedAt:serverTimestamp()});toast('Personalização salva.')}}
